// // This module implements a 16-bit SRAM with a 4-bit address bus, 16-bit data buses, and separate write and chip enable signals.
module sram_cell (  
    input wire [15:0] data_in,  
    input wire [3:0] addr,  
    input wire we,  
    input wire ce,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory [15:0];  

    always @(posedge ce) begin  
        if (we)  
            memory[addr] <= data_in;  
        else  
            data_out <= memory[addr];  
    end  
endmodule
